  // brace-init: stat_double d = {{2.4,-3.7,1.0,-2.1,0.5}, -0.9};\r
  // pre-loop init: mystery = 0.0\r
  //\r
  // i=1  -> -3.7 > 0 ? false, skip\r
  // i=2  -> 1.0  + 0.0 = 1.0\r
  // i=3  -> -2.1 > 0 ? false, skip\r
  // i=4  -> 0.5  + 1.0 = 1.5\r
